<script setup lang="ts">
import { computed, onMounted, reactive, ref } from 'vue'
import { ApiError, apiRequest, authState } from '../auth'
import type { Material, Product, ProductCategory, ProductPage } from '../product'
import AppShell from '../components/AppShell.vue'

const products = ref<Product[]>([]); const categories = ref<ProductCategory[]>([]); const materials = ref<Material[]>([]); const loading = ref(true); const errorMessage = ref(''); const message = ref(''); const showProduct = ref(false); const showCategory = ref(false); const editTarget = ref<Product | null>(null)
const canManage = computed(() => authState.user?.permissions.includes('product.manage') ?? false)
const canReadMaterials = computed(() => authState.user?.permissions.includes('material.read') ?? false)
const categoryForm = reactive({ code: '', name: '', sort_order: 0 })
const form = reactive({ name: '', category_id: '', summary: '', description: '', specifications_text: '', cover_material_id: '', video_material_id: '', video_url: '', gallery_material_ids: [] as string[], attachment_material_ids: [] as string[], sort_order: 0 })
async function load() { loading.value = true; try { const [page, categoryValues, materialValues] = await Promise.all([apiRequest<ProductPage>('/tenant/products?limit=100'), apiRequest<ProductCategory[]>('/tenant/product-categories'), canReadMaterials.value ? apiRequest<Material[]>('/tenant/materials') : Promise.resolve([])]); products.value = page.items; categories.value = categoryValues; materials.value = materialValues } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '产品数据加载失败' } finally { loading.value = false } }
async function createCategory() { try { await apiRequest('/tenant/product-categories', { method: 'POST', body: JSON.stringify(categoryForm) }); Object.assign(categoryForm, { code: '', name: '', sort_order: 0 }); showCategory.value = false; await load() } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '分类创建失败' } }
function resetProduct() { Object.assign(form, { name: '', category_id: '', summary: '', description: '', specifications_text: '', cover_material_id: '', video_material_id: '', video_url: '', gallery_material_ids: [], attachment_material_ids: [], sort_order: 0 }); editTarget.value = null; showProduct.value = false }
function edit(product: Product) { editTarget.value = product; showProduct.value = true; Object.assign(form, { name: product.name, category_id: product.category_id ?? '', summary: product.summary ?? '', description: product.description ?? '', specifications_text: Object.entries(product.specifications).map(([key, value]) => `${key}: ${value}`).join('\n'), cover_material_id: product.cover_material_id ?? '', video_material_id: product.video_material_id ?? '', video_url: product.video_url ?? '', gallery_material_ids: [...product.gallery_material_ids], attachment_material_ids: [...product.attachment_material_ids], sort_order: product.sort_order }) }
function specifications() { return Object.fromEntries(form.specifications_text.split('\n').map(line => line.split(':')).filter(parts => parts.length > 1 && parts[0].trim()).map(parts => [parts.shift()!.trim(), parts.join(':').trim()])) }
async function saveProduct() { const { specifications_text: _, ...values } = form; const payload = { ...values, category_id: form.category_id || null, cover_material_id: form.cover_material_id || null, video_material_id: form.video_material_id || null, video_url: form.video_url || null, summary: form.summary || null, description: form.description || null, specifications: specifications() }; try { if (editTarget.value) await apiRequest(`/tenant/products/${editTarget.value.id}`, { method: 'PATCH', body: JSON.stringify(payload) }); else await apiRequest('/tenant/products', { method: 'POST', body: JSON.stringify(payload) }); message.value = '产品资料已保存'; resetProduct(); await load() } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '产品保存失败' } }
async function setStatus(product: Product, status: 'published' | 'offline') { try { await apiRequest(`/tenant/products/${product.id}/status`, { method: 'POST', body: JSON.stringify({ status }) }); await load() } catch (error) { errorMessage.value = error instanceof ApiError ? error.message : '产品状态更新失败' } }
onMounted(load)
</script>

<template><AppShell><header class="page-header compact"><div><p class="eyebrow">PRODUCT CENTER</p><h1>产品中心</h1><p>{{ canManage ? '维护企业产品、案例和销售资料，并发布到数字名片。' : '浏览企业已维护的产品、案例和销售资料。' }}</p></div><div v-if="canManage" class="header-actions"><button class="secondary-button" @click="showCategory = true">新增分类</button><button class="primary-button" @click="showProduct = true">新增产品</button></div></header><div v-if="message" class="notice success">{{ message }}</div><div v-if="errorMessage" class="notice error">{{ errorMessage }}</div><section class="panel table-panel"><div v-if="loading" class="empty-state">正在加载产品…</div><div v-else-if="!products.length" class="empty-state">暂无产品</div><table v-else><thead><tr><th>产品</th><th>分类</th><th>排序</th><th>素材</th><th>状态</th><th v-if="canManage">操作</th></tr></thead><tbody><tr v-for="product in products" :key="product.id"><td><b>{{ product.name }}</b><small>{{ product.summary || '暂无摘要' }}</small></td><td>{{ categories.find(item => item.id === product.category_id)?.name || '未分类' }}</td><td>{{ product.sort_order }}</td><td>{{ product.cover_material_id ? '有封面' : '无封面' }}</td><td><span class="pill" :class="{ inactive: product.status !== 'published' }">{{ product.status === 'draft' ? '草稿' : product.status === 'published' ? '已发布' : '已下线' }}</span></td><td v-if="canManage" class="actions"><button class="link-button" @click="edit(product)">编辑</button><button v-if="product.status !== 'published'" class="link-button" @click="setStatus(product, 'published')">发布</button><button v-else class="link-button danger" @click="setStatus(product, 'offline')">下线</button></td></tr></tbody></table></section><div v-if="showCategory && canManage" class="modal-backdrop" @click.self="showCategory = false"><form class="modal" @submit.prevent="createCategory"><p class="eyebrow">CATEGORY</p><h2>新增产品分类</h2><label><span>分类编号</span><input v-model.trim="categoryForm.code" required /></label><label><span>分类名称</span><input v-model.trim="categoryForm.name" required /></label><label><span>排序</span><input v-model.number="categoryForm.sort_order" type="number" min="0" /></label><div class="modal-actions"><button type="button" class="secondary-button" @click="showCategory = false">取消</button><button class="primary-button">创建</button></div></form></div><div v-if="showProduct && canManage" class="modal-backdrop" @click.self="resetProduct"><form class="modal product-modal" @submit.prevent="saveProduct"><p class="eyebrow">PRODUCT</p><h2>{{ editTarget ? '编辑产品' : '新增产品' }}</h2><div class="modal-grid"><label><span>产品名称</span><input v-model.trim="form.name" required /></label><label><span>分类</span><select v-model="form.category_id"><option value="">未分类</option><option v-for="category in categories.filter(item => item.is_active)" :key="category.id" :value="category.id">{{ category.name }}</option></select></label><label class="full-row"><span>摘要</span><input v-model.trim="form.summary" /></label><label class="full-row"><span>详细介绍</span><textarea v-model.trim="form.description" rows="5" /></label><label class="full-row"><span>规格参数（每行“名称: 内容”）</span><textarea v-model="form.specifications_text" rows="4" placeholder="尺寸: 120 × 80 mm&#10;材质: 铝合金" /></label><label><span>封面图片</span><select v-model="form.cover_material_id"><option value="">请选择</option><option v-for="material in materials.filter(item => item.kind === 'image')" :key="material.id" :value="material.id">{{ material.name }}（{{ material.access === 'public' ? '公开' : '私有' }}）</option></select></label><label><span>视频素材</span><select v-model="form.video_material_id"><option value="">不使用</option><option v-for="material in materials.filter(item => item.kind === 'video')" :key="material.id" :value="material.id">{{ material.name }}</option></select></label><label><span>外部视频链接</span><input v-model.trim="form.video_url" type="url" /></label><label><span>排序</span><input v-model.number="form.sort_order" type="number" min="0" /></label><label class="full-row"><span>图集（可多选）</span><select v-model="form.gallery_material_ids" multiple><option v-for="material in materials.filter(item => item.kind === 'image')" :key="material.id" :value="material.id">{{ material.name }}</option></select></label><label class="full-row"><span>PDF 附件（可多选）</span><select v-model="form.attachment_material_ids" multiple><option v-for="material in materials.filter(item => item.kind === 'pdf')" :key="material.id" :value="material.id">{{ material.name }}</option></select></label></div><div class="modal-actions"><button type="button" class="secondary-button" @click="resetProduct">取消</button><button class="primary-button">保存产品</button></div></form></div></AppShell></template>
